		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	}

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{changeZ, changeA, changeM},
		},
	}

	result := formatter.Format(plan, &schemarepo.Schemas{})

	// Check that resources appear in sorted order
	posApple := findIndex(result, "aws_instance.apple")
	posMonkey := findIndex(result, "aws_instance.monkey")
	posZebra := findIndex(result, "aws_instance.zebra")

	if posApple == -1 || posMonkey == -1 || posZebra == -1 {
		t.Error("Not all resources found in output")
	} else if posApple > posMonkey || posMonkey > posZebra {
		t.Errorf("Resources not in sorted order. Got:\n%s", result)
	}
}

// Helper functions

func contains(s, substr string) bool {
	// Simple substring check
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

func findIndex(s, substr string) int {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return i
		}
	}
	return -1
}

